function TechItem({ tech }: { tech: typeof technologies[0] }) {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 })
  const itemRef = useRef<HTMLDivElement>(null)

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!itemRef.current) return
    const rect = itemRef.current.getBoundingClientRect()
    setMousePosition({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    })
  }

  return (
    <div
      ref={itemRef}
      onMouseMove={handleMouseMove}
      className="group relative flex items-center justify-center rounded-xl border border-slate-800 bg-slate-900/50 p-6 md:p-8 transition-all duration-300 hover:border-indigo-500/50 overflow-hidden shrink-0 w-32 md:w-40"
    >
      <div 
        className="pointer-events-none absolute inset-0 opacity-0 transition-opacity duration-300 group-hover:opacity-100"
        style={{
          background: `radial-gradient(400px circle at ${mousePosition.x}px ${mousePosition.y}px, rgba(99, 102, 241, 0.15), transparent 40%)`
        }}
      />
      <div className="relative z-10 flex flex-col items-center gap-3">
        <div className="text-slate-400 group-hover:text-indigo-300 transition-colors duration-300">
          <TechLogo name={tech.logo} />
        </div>
        <span className="text-xs md:text-sm text-slate-500 group-hover:text-indigo-300 transition-colors duration-300 font-medium">
          {tech.name}
        </span>
      </div>
    </div>
  )
}

export function TechCarousel() {
  const [isVisible, setIsVisible] = useState(false)
  const sectionRef = useRef<HTMLElement>(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
        }
      },
      { threshold: 0.1 }
    )

    if (sectionRef.current) {
      observer.observe(sectionRef.current)
    }

    return () => observer.disconnect()
  }, [])

  return (
    <section ref={sectionRef} className="py-16 lg:py-20 relative overflow-hidden">
      <div className="container mx-auto px-4 sm:px-6 mb-10">
        <div className={`text-center transition-all duration-700 ${
          isVisible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"
        }`}>
          <span className="inline-block px-4 py-1.5 rounded-full bg-primary/10 text-primary text-sm font-medium mb-4">
            Tecnologias
          </span>
          <h2 className="text-2xl sm:text-3xl font-bold tracking-tight text-balance">
            Usamos las mejores herramientas del mercado
          </h2>
        </div>
      </div>
      
      {/* Marquee container */}
      <div className={`relative transition-all duration-700 delay-200 ${
        isVisible ? "opacity-100" : "opacity-0"
      }`}>
        <div className="flex animate-marquee gap-6">
          {[...technologies, ...technologies, ...technologies].map((tech, index) => (
            <TechItem key={`${tech.name}-${index}`} tech={tech} />
          ))}
        </div>
      </div>
    </section>
  )
}
